using UnityEngine;

/// <summary>
/// Botar ovo (P5 — "a galinha bota o ovo"): instancia o "eggPrefab" da forma
/// (P1) atrás do player. O ovo é um objecto PESADO (prefab com EggObject +
/// ObjectWeight + Carryable): dá dano ao cair em cima de inimigos, pressiona
/// placas de peso, e pode ser carregado/atirado por formas com canGrab/canThrow.
///
/// Activado via PrimaryAbility.Egg (AbilityRouter.OnAbilityPressed → TryLayEgg).
/// </summary>
[RequireComponent(typeof(PlayerMotor2D))]
public class EggAbility : MonoBehaviour, IFormAbility, IAbility, IActiveAbility
{
    [Header("Spawn")]
    [Tooltip("Deslocamento do ovo em relação ao player (X é espelhado para 'atrás' conforme o facing).")]
    public Vector2 spawnOffset = new Vector2(-0.6f, 0.2f);

    [Tooltip("Máximo de ovos deste player em simultâneo (0 = sem limite). O mais antigo é destruído ao exceder.")]
    [Min(0)] public int maxEggsAlive = 2;

    private PlayerMotor2D motor;

    private bool enabledForForm;
    private GameObject eggPrefab;
    private float cooldown = 3f;
    private float cooldownTimer;

    private readonly System.Collections.Generic.Queue<GameObject> _eggs = new System.Collections.Generic.Queue<GameObject>();

    private void Awake()
    {
        motor = GetComponent<PlayerMotor2D>();
    }

    private void Update()
    {
        if (cooldownTimer > 0f) cooldownTimer -= Time.deltaTime;
    }

    public void ConfigureFromForm(AnimalFormData form)
    {
        enabledForForm = form != null && form.primaryAbility == PrimaryAbility.Egg && form.eggPrefab != null;
        eggPrefab = form != null ? form.eggPrefab : null;
        cooldown = form != null ? Mathf.Max(0.2f, form.eggCooldown) : 3f;
    }

    /// <summary>Bota um ovo (AbilityRouter — PrimaryAbility.Egg).</summary>
    public void TryLayEgg()
    {
        if (!enabledForForm || cooldownTimer > 0f) return;

        cooldownTimer = cooldown;

        int dir = motor.FacingSign != 0 ? motor.FacingSign : 1;
        Vector3 pos = transform.position + new Vector3(spawnOffset.x * dir, spawnOffset.y, 0f);

        var egg = Instantiate(eggPrefab, pos, Quaternion.identity);
        _eggs.Enqueue(egg);

        // Limite de ovos vivos: remove o mais antigo.
        while (maxEggsAlive > 0 && _eggs.Count > maxEggsAlive)
        {
            var oldest = _eggs.Dequeue();
            if (oldest != null) Destroy(oldest);
        }
    }

    // ---- IAbility / IActiveAbility (Tarefa #34 — HUD) ----
    // Instantânea, sem estado persistente — só o cooldown importa para a HUD.
    void IAbility.Activate() => TryLayEgg();
    void IAbility.Release() { }
    public void Cancel(AbilityCancelReason reason) { }
    public float CooldownRemaining => Mathf.Max(0f, cooldownTimer);
    bool IAbility.IsActive => false;
    public float CooldownDuration => cooldown;
    public bool CanActivate => enabledForForm && cooldownTimer <= 0f;

    /// <summary>AnimalsDebugPanel — zera o cooldown de pôr ovo.</summary>
    public void ResetCooldown() => cooldownTimer = 0f;
}
